import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './Header.css';

const PUBLIC_NAV = [
  { label: '서비스 소개', href: '/#features' },
  { label: '제품 체험', href: '/#chat-demo' },
  { label: '이용 방법', href: '/#how-it-works' },
  { label: '다운로드', href: '/#download' },
  { label: 'FAQ', href: '/#faq' },
];

function Header() {
  const navigate = useNavigate();
  const location = useLocation();
  const { isLoggedIn, isAdmin, logout } = useAuth();

  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 12);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname, location.hash]);

  useEffect(() => {
    document.body.classList.toggle('menu-open', menuOpen);
    return () => document.body.classList.remove('menu-open');
  }, [menuOpen]);

  const closeMenu = () => setMenuOpen(false);

  const handleLogout = () => {
    logout();
    navigate('/');
    closeMenu();
  };

  const renderPublicLinks = () =>
    PUBLIC_NAV.map((item) => (
      <a key={item.href} href={item.href} className="nav-link" onClick={closeMenu}>
        <span>{item.label}</span>
      </a>
    ));

  const renderPrivateLinks = () => (
    <>
      <Link to="/dashboard" className="nav-link" onClick={closeMenu}>
        <span>대시보드</span>
      </Link>
      {isAdmin && (
        <Link to="/admin" className="nav-link" onClick={closeMenu}>
          <span>관리자</span>
        </Link>
      )}
      <Link to="/mypage" className="nav-link" onClick={closeMenu}>
        <span>마이페이지</span>
      </Link>
    </>
  );

  return (
    <>
      <header className={`header ${scrolled ? 'scrolled' : ''}`}>
        <div className="container header-inner">
          <Link to="/" className="brand">
            <div className="brand-mark">
              <span className="brand-ring"></span>
              <span className="brand-dot"></span>
            </div>

            <div className="brand-copy">
              <strong>메이티</strong>
              <span>AI Emotion Companion</span>
            </div>
          </Link>

          <nav className="nav-desktop">
            {!isLoggedIn ? renderPublicLinks() : renderPrivateLinks()}
          </nav>

          <div className="header-actions">
            {!isLoggedIn ? (
              <>
                <button className="btn ghost-btn" onClick={() => navigate('/login')}>
                  로그인
                </button>
                <button className="btn btn-primary" onClick={() => navigate('/signup')}>
                  무료 체험 시작
                </button>
              </>
            ) : (
              <>
                <div className="user-chip">
                  <span className="status-dot"></span>
                  {isAdmin ? '관리자 모드' : '로그인됨'}
                </div>

                <button className="btn logout-btn" onClick={handleLogout}>
                  로그아웃
                </button>
              </>
            )}
          </div>

          <button
            className={`hamburger ${menuOpen ? 'active' : ''}`}
            aria-label="모바일 메뉴 열기"
            onClick={() => setMenuOpen((prev) => !prev)}
          >
            <span></span>
            <span></span>
            <span></span>
          </button>
        </div>
      </header>

      <div className={`mobile-overlay ${menuOpen ? 'open' : ''}`} onClick={closeMenu}></div>

      <aside className={`mobile-drawer ${menuOpen ? 'open' : ''}`}>
        <div className="mobile-drawer-inner">
          <div className="mobile-top">
            <div className="mobile-brand">메이티</div>
            <button className="mobile-close" onClick={closeMenu}>
              ✕
            </button>
          </div>

          <div className="mobile-nav">
            {!isLoggedIn ? renderPublicLinks() : renderPrivateLinks()}
          </div>

          <div className="mobile-bottom-glass">
            {!isLoggedIn ? (
              <>
                <button
                  className="btn btn-secondary"
                  onClick={() => {
                    closeMenu();
                    navigate('/login');
                  }}
                >
                  로그인
                </button>
                <button
                  className="btn btn-primary"
                  onClick={() => {
                    closeMenu();
                    navigate('/signup');
                  }}
                >
                  무료 체험 시작
                </button>
              </>
            ) : (
              <button className="btn logout-btn" onClick={handleLogout}>
                로그아웃
              </button>
            )}
          </div>
        </div>
      </aside>
    </>
  );
}

export default Header;
